export const getSmsWebhookUrl = () => {
  return `/api/sms/webhook`;
};

export const smsWebhook = async (
  smsWebhookBody: SmsWebhookBody,
  options?: RequestInit,
): Promise<string> => {
  const formUrlEncoded = new URLSearchParams();
  if (smsWebhookBody.Body !== undefined) {
    formUrlEncoded.append(`Body`, smsWebhookBody.Body);
  }
  if (smsWebhookBody.From !== undefined) {
    formUrlEncoded.append(`From`, smsWebhookBody.From);
  }
  if (smsWebhookBody.To !== undefined) {
    formUrlEncoded.append(`To`, smsWebhookBody.To);
  }

  return customFetch<string>(getSmsWebhookUrl(), {
    ...options,
    method: "POST",
    headers: {
      "Content-Type": "application/x-www-form-urlencoded",
      ...options?.headers,
    },
    body: formUrlEncoded,
  });
};

